iterateActiveLinks(activeLinkIds);

wfcontext.getTaskResult().setAttribute(thisApp.getName() + "-orphanLinks", orphanLinks);
wfcontext.getTaskResult().setAttribute(thisApp.getName() + "-compliantLinks", compliantLinks);
wfcontext.getTaskResult().setAttribute(thisApp.getName() + "-noncompliantLinks", noncompliantLinks);
wfcontext.getTaskResult().setAttribute(thisApp.getName() + "-outOfScopeLinks", outOfScopeLinks);

Util.flushIterator(activeLinkIds);

import sailpoint.object.Argument;
import sailpoint.object.Signature;
import sailpoint.object.TaskDefinition;

//Add Arguments to Returns in TaskDefinition

Argument arg1 = new Argument();
arg1.setName(thisApp.getName() + "-totalActiveLinks");
arg1.setType("int");
arg1.setPrompt(thisApp.getName() + " - Total Active Links");

Argument arg2 = new Argument();
arg2.setName(thisApp.getName() + "-compliantLinks");
arg2.setType("int");
arg2.setPrompt(thisApp.getName() + " - Total Compliant Links");

Argument arg3 = new Argument();
arg3.setName(thisApp.getName() + "-noncompliantLinks");
arg3.setType("int");
arg3.setPrompt(thisApp.getName() + " - Total Noncompliant Links");

Argument arg4 = new Argument();
arg4.setName(thisApp.getName() + "-orphanLinks");
arg4.setType("int");
arg4.setPrompt(thisApp.getName() + " - Total Orphan Links (Ignored)");

Argument arg5 = new Argument();
arg5.setName(thisApp.getName() + "-outOfScopeLinks");
arg5.setType("int");
arg5.setPrompt(thisApp.getName() + " - Total Out of Scope Links (Ignored)");

Signature sig = wfcontext.getTaskResult().getDefinition().getSignature();
sig.getReturns().add(arg1);
sig.getReturns().add(arg2);
sig.getReturns().add(arg3);
sig.getReturns().add(arg4);
sig.getReturns().add(arg5);

//Add Total Active Links to TaskResult

wfcontext.getTaskResult().setAttribute(thisApp.getName() + "-totalActiveLinks", totalActiveLinks);
